-- в”Ђв”Ђ Wingfit в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
UPDATE tools SET
  short_description = COALESCE($q$Open-source, self-hosted fitness app for planning workouts, tracking personal records, and syncing smartwatch data, built with no telemetry and no subscriptions.$q$, short_description),
  pricing_model = COALESCE($q$open-source$q$, pricing_model),
  starting_price = COALESCE($q$Free (self-hosted); no paid tiers$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE($q$Independent open-source project maintained by a single developer$q$, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Wingfit Review 2026: Self-Hosted, Open-Source Fitness Tracking App$q$, seo_title),
  seo_meta_description = COALESCE($q$See how Wingfit's open-source, self-hosted app lets you plan workouts, track personal records, and sync smartwatch data with no subscriptions or tracking.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Wingfit is a minimalist, open-source fitness application built to let individuals plan workouts, track personal records, and use smartwatch data without relying on a commercial subscription service. The project is developed and maintained on GitHub by a developer using the handle itskovacs, and its live demo runs at wingfit.fr. Unlike typical gym or fitness SaaS products, Wingfit is explicitly designed as a privacy-first, self-hosted tool: it includes no telemetry or tracking of any kind, has no subscriptions, no premium tiers, and no feature gating, and the project's philosophy is summarized in its own tagline that users own their data. The application is released under the Creative Commons BY-NC-SA 4.0 license, which allows people to inspect, modify, and share the code with attribution, while prohibiting commercial redistribution. Technically, Wingfit is built with an Angular 19 and PrimeNG frontend paired with a FastAPI backend and a SQLite database, and it is packaged for straightforward self-hosting through Docker, either via Docker Compose (the recommended method) or a direct Docker run command, with data persisted to a local storage volume. The app is also available through the Umbrel App Store, making it easy to deploy on home server and self-hosting setups popular among privacy-conscious users. Functionally, Wingfit lets users plan and organize workouts, log and monitor personal records over time, review statistics and progress, and manage structured workout blocks and sessions, while leveraging data pulled in from smartwatches rather than locking users into a single proprietary fitness ecosystem. As of its most recent tracked release, version 5.3.1 from August 2025, the project had accumulated over 500 stars on GitHub, reflecting a modest but genuinely engaged self-hosting and open-source community rather than a commercial customer base. There is no company behind Wingfit in the traditional SaaS sense, no publicly stated founding year for the project, and no venture funding or enterprise sales motion; it is best understood as a solo-maintained, open-source alternative to subscription fitness-tracking apps, aimed at people who want full control over their workout and health data. Because it has no built-in billing, member management, or class-scheduling features, Wingfit is not a substitute for commercial gym or studio management software; it is a personal training log and workout planner intended for individual athletes and self-hosting enthusiasts.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'aa9d2774-9a4d-4792-8ad7-4de1b095e3bf';

