INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('758cebc7-97dc-4ae8-9b04-1a2c822140e0', $q$Daily Rank Tracker$q$, $q$Monitors Google rankings for tracked keywords every day and displays progress in visual dashboards.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('758cebc7-97dc-4ae8-9b04-1a2c822140e0', $q$Local Rank Tracker$q$, $q$Tracks local and geo-specific search visibility for businesses targeting particular regions or cities.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('758cebc7-97dc-4ae8-9b04-1a2c822140e0', $q$Keyword Explorer$q$, $q$Researches new keyword opportunities with search volume and difficulty scoring.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('758cebc7-97dc-4ae8-9b04-1a2c822140e0', $q$Keyword Gap Analysis$q$, $q$Compares a website's keyword footprint against competitors to surface missed opportunities.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('758cebc7-97dc-4ae8-9b04-1a2c822140e0', $q$SERP Benchmark$q$, $q$Benchmarks a page against Google's top 10 results for a target keyword to understand ranking factors.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('758cebc7-97dc-4ae8-9b04-1a2c822140e0', $q$On-Page SEO Checker$q$, $q$Provides page-level recommendations for improving on-page optimization.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('758cebc7-97dc-4ae8-9b04-1a2c822140e0', $q$AI Content Outliner$q$, $q$Generates content outlines using AI based on keyword and SERP insights.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('758cebc7-97dc-4ae8-9b04-1a2c822140e0', $q$Automated White-Label Reporting$q$, $q$Schedules customizable, brandable SEO reports for clients or stakeholders.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('758cebc7-97dc-4ae8-9b04-1a2c822140e0', $q$Simple, intuitive interface that is easy to onboard onto quickly$q$, 0);
