INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('758cebc7-97dc-4ae8-9b04-1a2c822140e0', $q$Strong review scores across Capterra, G2, and Google$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('758cebc7-97dc-4ae8-9b04-1a2c822140e0', $q$Useful integrations with WordPress, Wix, and Looker Studio$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('758cebc7-97dc-4ae8-9b04-1a2c822140e0', $q$Keyword tracking limits mean larger sites need higher-priced tiers$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('758cebc7-97dc-4ae8-9b04-1a2c822140e0', $q$Fewer advanced backlink and technical SEO audit features than full suites like Ahrefs or Semrush$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('758cebc7-97dc-4ae8-9b04-1a2c822140e0', $q$Enterprise-level needs require a custom quote rather than transparent self-serve pricing$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('758cebc7-97dc-4ae8-9b04-1a2c822140e0', $q$Local tracking and reporting depth may feel basic for very large agencies$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('758cebc7-97dc-4ae8-9b04-1a2c822140e0', $q$What is Wincher used for?$q$, $q$Wincher is used to track Google search rankings daily, research keywords, analyze competitor keyword gaps, and generate automated SEO reports.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('758cebc7-97dc-4ae8-9b04-1a2c822140e0', $q$Does Wincher offer a free trial?$q$, $q$Yes, Wincher offers a 7-day free trial of its Pro plan before requiring a paid subscription.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('758cebc7-97dc-4ae8-9b04-1a2c822140e0', $q$How much does Wincher cost?$q$, $q$Plans start at 49 per month for the Basic tier, with Standard at 89 per month and Professional at 319 per month, plus a custom Enterprise option for larger needs.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('758cebc7-97dc-4ae8-9b04-1a2c822140e0', $q$Does Wincher track local search rankings?$q$, $q$Yes, Wincher includes a dedicated Local Rank Tracker for monitoring geo-specific search visibility.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('758cebc7-97dc-4ae8-9b04-1a2c822140e0', $q$What integrations does Wincher support?$q$, $q$Wincher integrates with WordPress, Wix, and Google Looker Studio for reporting and data connections.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('758cebc7-97dc-4ae8-9b04-1a2c822140e0', $q$Is Wincher good for agencies?$q$, $q$Yes, higher tiers support unlimited websites and multiple users, plus white-label reporting, making it suitable for agencies managing multiple clients.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('758cebc7-97dc-4ae8-9b04-1a2c822140e0', $q$Does Wincher offer white-label reports?$q$, $q$Yes, automated reports can be scheduled and customized with white-label branding.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('758cebc7-97dc-4ae8-9b04-1a2c822140e0', $q$What is the difference between the Basic, Standard, and Professional plans?$q$, $q$The plans differ mainly in tracked keyword volume (500, 1,000, and 5,000 respectively) and website limits, with higher tiers unlocking unlimited websites and more users.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('758cebc7-97dc-4ae8-9b04-1a2c822140e0', $q$Small business rank monitoring$q$, $q$Owners track how their site ranks for core commercial keywords over time without needing an enterprise SEO team.$q$, $q$Small business owners$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('758cebc7-97dc-4ae8-9b04-1a2c822140e0', $q$Agency client reporting$q$, $q$Agencies track rankings across many client sites and automate white-label reports for stakeholders.$q$, $q$Digital marketing agencies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('758cebc7-97dc-4ae8-9b04-1a2c822140e0', $q$In-house SEO management$q$, $q$Marketing teams use keyword research and gap analysis to prioritize content and on-page fixes.$q$, $q$In-house marketing and SEO teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('758cebc7-97dc-4ae8-9b04-1a2c822140e0', $q$Basic$q$, $q$EUR49$q$, $q$monthly (annual available with 2 months free)$q$, NULL, $q$["500 tracked keywords","Up to 10 websites","1 user","Rank tracking and reporting"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('758cebc7-97dc-4ae8-9b04-1a2c822140e0', $q$Standard$q$, $q$EUR89$q$, $q$monthly (annual available with 2 months free)$q$, NULL, $q$["1,000 tracked keywords","Unlimited websites","Multiple users","Advanced research tools"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('758cebc7-97dc-4ae8-9b04-1a2c822140e0', $q$Professional$q$, $q$EUR319$q$, $q$monthly (annual available with 2 months free)$q$, NULL, $q$["5,000 tracked keywords","Unlimited websites","Multiple users","Full feature access for agencies"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('758cebc7-97dc-4ae8-9b04-1a2c822140e0', $q$Enterprise$q$, $q$Custom$q$, $q$custom quote$q$, NULL, $q$["Tailored keyword volume","Dedicated support","Custom reporting needs"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('758cebc7-97dc-4ae8-9b04-1a2c822140e0', $q$overview$q$, $q$What Is Wincher$q$, 2, ARRAY[$q$Wincher is an SEO rank tracking platform built to help small businesses, marketers, and agencies keep tabs on their search visibility without the complexity of a full enterprise SEO suite. Founded in Stockholm in 2014, the company has grown into a tool used by hundreds of thousands of marketers and business owners worldwide, with a particular focus on daily rank tracking and keyword insight.$q$, $q$The platform's central feature is its rank tracker, which checks Google rankings for tracked keywords on a daily basis and presents the results in intuitive, visual dashboards. This makes it easy to spot ranking gains, losses, and volatility over time, whether for a single website or a portfolio of client sites managed by an agency.$q$, $q$Beyond tracking, Wincher layers in research and optimization tools, including keyword discovery, competitor gap analysis, and on-page recommendations, positioning itself as a lightweight but complete toolkit for ongoing SEO management rather than a one-off audit tool.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('758cebc7-97dc-4ae8-9b04-1a2c822140e0', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The Rank Tracker and Local Rank Tracker form the backbone of Wincher, monitoring both national and local search rankings so businesses with physical locations or regional targeting can see how they perform in specific geographies.$q$, $q$The Keyword Explorer and Keyword Gap Analysis tools help users find new keyword opportunities and identify terms that competitors rank for but the user does not, while the SERP Benchmark feature compares a page directly against Google's top 10 results to reveal what is driving those rankings.$q$, $q$An On-Page SEO Checker gives page-specific optimization guidance, and an AI Content Outliner uses keyword and SERP data to generate content outlines. For teams that report to clients or stakeholders, Wincher supports automated, white-labeled reporting on a schedule, along with integrations for WordPress, Wix, and Google Looker Studio.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('758cebc7-97dc-4ae8-9b04-1a2c822140e0', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Wincher offers three core subscription tiers priced in EUR or USD: Basic at 49 per month (500 tracked keywords across up to 10 websites), Standard at 89 per month (1,000 keywords, unlimited websites), and Professional at 319 per month (5,000 keywords, unlimited websites and users).$q$, $q$Each plan can be billed monthly or annually, and annual billing includes two months free compared to paying monthly. Businesses with larger tracking needs than the Professional tier can contact Wincher directly for a custom Enterprise quote.$q$, $q$New customers can try the platform with a 7-day free trial of the Pro plan before subscribing, and there is no long-term contract requirement beyond the chosen billing cycle.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('029723bb-0e7c-43dd-958e-73d6dbd7933b', $q$Multi-language script execution$q$, $q$Runs and orchestrates scripts written in Python, TypeScript, Go, PHP, Bash, and SQL.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('029723bb-0e7c-43dd-958e-73d6dbd7933b', $q$DAG-based flows$q$, $q$Represents multi-step workflows as directed acyclic graphs capturing task dependencies.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('029723bb-0e7c-43dd-958e-73d6dbd7933b', $q$Auto-generated interfaces$q$, $q$Automatically creates user interfaces for scripts and flows so they can be used as internal apps.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('029723bb-0e7c-43dd-958e-73d6dbd7933b', $q$High-throughput job orchestration$q$, $q$Executes scheduled and triggered jobs with a focus on speed and reliability.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('029723bb-0e7c-43dd-958e-73d6dbd7933b', $q$Git-based collaboration$q$, $q$Versions entire workspaces in Git for team-based development and review.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('029723bb-0e7c-43dd-958e-73d6dbd7933b', $q$Enterprise access controls$q$, $q$Provides RBAC, SSO, SAML with group sync, secret management, and audit logs.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('029723bb-0e7c-43dd-958e-73d6dbd7933b', $q$Self-hosting options$q$, $q$Deployable via Docker, AWS Fargate, or Kubernetes for full infrastructure control.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('029723bb-0e7c-43dd-958e-73d6dbd7933b', $q$Advanced observability$q$, $q$Integrates with Prometheus and OpenTelemetry for monitoring and tracing on Enterprise plans.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('029723bb-0e7c-43dd-958e-73d6dbd7933b', $q$Genuinely free, full-featured open-source self-hosted tier$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('029723bb-0e7c-43dd-958e-73d6dbd7933b', $q$No vendor lock-in since logic is written in mainstream programming languages$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('029723bb-0e7c-43dd-958e-73d6dbd7933b', $q$Fast job execution engine suited to high-throughput automation$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('029723bb-0e7c-43dd-958e-73d6dbd7933b', $q$Supports a wide range of languages in one platform$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('029723bb-0e7c-43dd-958e-73d6dbd7933b', $q$Backed by credible investors and growing enterprise customer base$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('029723bb-0e7c-43dd-958e-73d6dbd7933b', $q$Requires coding skills, making it less accessible to non-technical users than pure low-code tools$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('029723bb-0e7c-43dd-958e-73d6dbd7933b', $q$Enterprise features like SAML group sync and unlimited audit logs are gated behind the paid tier$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('029723bb-0e7c-43dd-958e-73d6dbd7933b', $q$Per-seat and per-worker add-on pricing can increase Enterprise costs as usage grows$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('029723bb-0e7c-43dd-958e-73d6dbd7933b', $q$Smaller community and ecosystem compared to more established automation platforms$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('029723bb-0e7c-43dd-958e-73d6dbd7933b', $q$What is Windmill used for?$q$, $q$Windmill is used to turn scripts into internal tools, automated workflows, and scheduled jobs for engineering and data teams.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('029723bb-0e7c-43dd-958e-73d6dbd7933b', $q$Is Windmill free?$q$, $q$Yes, Windmill has a free, open-source self-hosted tier with unlimited executions and support for up to 50 users.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('029723bb-0e7c-43dd-958e-73d6dbd7933b', $q$What languages does Windmill support?$q$, $q$Windmill supports Python, TypeScript, Go, PHP, Bash, and SQL for building scripts, flows, and apps.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('029723bb-0e7c-43dd-958e-73d6dbd7933b', $q$Can Windmill be self-hosted?$q$, $q$Yes, Windmill can be self-hosted using Docker, AWS Fargate, or Kubernetes.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('029723bb-0e7c-43dd-958e-73d6dbd7933b', $q$How much does the Windmill Enterprise plan cost?$q$, $q$Enterprise pricing starts at 120 per month, with additional per-seat and per-worker add-ons for developers, operators, and workers.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('029723bb-0e7c-43dd-958e-73d6dbd7933b', $q$Who founded Windmill?$q$, $q$Windmill was founded in 2022 by Ruben Fiszel and is backed by Y Combinator and investors including Bessemer Venture Partners.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('029723bb-0e7c-43dd-958e-73d6dbd7933b', $q$Does Windmill support single sign-on?$q$, $q$Yes, SSO is supported, with SAML including group synchronization available on the Enterprise plan.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('029723bb-0e7c-43dd-958e-73d6dbd7933b', $q$How is Windmill different from tools like Retool or Airflow?$q$, $q$Windmill emphasizes plain code over proprietary building blocks, aiming for faster execution and a genuinely open-source self-hosted option.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('029723bb-0e7c-43dd-958e-73d6dbd7933b', $q$Internal tool building$q$, $q$Engineering teams turn scripts into internal apps and dashboards without building custom UIs from scratch.$q$, $q$Engineering and platform teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('029723bb-0e7c-43dd-958e-73d6dbd7933b', $q$Data pipeline automation$q$, $q$Data teams orchestrate multi-step data pipelines and scheduled jobs using DAG-based flows.$q$, $q$Data engineers and analysts$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('029723bb-0e7c-43dd-958e-73d6dbd7933b', $q$Operational automation$q$, $q$DevOps and operations teams automate recurring operational scripts and approvals with access controls.$q$, $q$DevOps and IT operations teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('029723bb-0e7c-43dd-958e-73d6dbd7933b', $q$Free and Open-Source$q$, $q$$0$q$, $q$self-hosted$q$, NULL, $q$["Unlimited executions","Up to 50 users","3 workspaces","10 GiB object storage","Community Discord support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('029723bb-0e7c-43dd-958e-73d6dbd7933b', $q$Enterprise$q$, $q$From $120 per month$q$, $q$monthly or annual$q$, NULL, $q$["Unlimited executions and workspaces","SAML with group sync","Unlimited audit logs and job retention","24/7 priority support","Advanced observability tooling"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('029723bb-0e7c-43dd-958e-73d6dbd7933b', $q$overview$q$, $q$What Is Windmill$q$, 2, ARRAY[$q$Windmill is an open-source, code-first orchestration platform designed for building internal software. Founded in 2022 by Ruben Fiszel and backed by Y Combinator and investors including Bessemer Venture Partners, the company operates out of Paris and San Francisco and has grown to serve thousands of organizations, including hundreds of enterprise customers.$q$, $q$The core idea behind Windmill is that internal tools, automations, and data pipelines should be built from ordinary code rather than proprietary low-code building blocks. Scripts written in Python, TypeScript, Go, PHP, Bash, or SQL can be turned directly into runnable tools, scheduled jobs, or multi-step workflows.$q$, $q$Windmill automatically generates user interfaces for scripts and flows, letting teams go from a raw script to a usable internal application quickly, while still keeping the underlying logic in standard, portable code rather than a vendor-specific format.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('029723bb-0e7c-43dd-958e-73d6dbd7933b', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Windmill supports multiple languages in a single platform and represents workflows as DAG-based flows that capture task dependencies, enabling complex automations and data pipelines to be built and visualized clearly.$q$, $q$Collaboration is Git-native, with entire workspaces version-controlled, and teams can share resources and set granular permissions across scripts, flows, and apps. Enterprise-grade controls include role-based access control, SSO, secret management, and audit logging.$q$, $q$The platform can be self-hosted via Docker, Fargate, or Kubernetes, or run on Windmill's managed cloud, and it emphasizes execution speed, positioning itself as one of the fastest job orchestrators available for internal tooling and automation use cases.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('029723bb-0e7c-43dd-958e-73d6dbd7933b', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Windmill follows an open-core pricing model. The Free and Open-Source tier costs nothing, supports unlimited executions, up to 50 users, three workspaces, and 10 GiB of object storage, with community Discord support and some limits such as 10 SSO users.$q$, $q$The Enterprise tier starts at 120 per month and unlocks unlimited workspaces, executions, audit logs, and job retention, along with SAML with group sync, distributed caching, advanced observability, and 24/7 priority support.$q$, $q$Enterprise pricing scales with optional add-ons, including developer seats at 20 per month, operator or external JWT user seats at 10 per month, and standard or native subworkers at 50 per month each, billed monthly or annually with no additional usage-based metering.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('029723bb-0e7c-43dd-958e-73d6dbd7933b', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('758d739b-574e-4253-96df-178cefd5f067', $q$Cascade AI agent$q$, $q$An agent with deep codebase context that plans and executes multi-file edits and commands.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('758d739b-574e-4253-96df-178cefd5f067', $q$Natural-language code generation$q$, $q$Generates code, documentation, and fixes from natural-language prompts.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('758d739b-574e-4253-96df-178cefd5f067', $q$Multi-IDE support$q$, $q$Available as a standalone editor and as plugins for VS Code and JetBrains IDEs.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('758d739b-574e-4253-96df-178cefd5f067', $q$Proactive debugging$q$, $q$Identifies and helps resolve issues across a project as changes are made.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('758d739b-574e-4253-96df-178cefd5f067', $q$Terminal command execution$q$, $q$Allows the AI agent to run and iterate on terminal commands as part of a task.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('758d739b-574e-4253-96df-178cefd5f067', $q$Multi-language support$q$, $q$Supports a wide range of programming languages for completion and generation.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('758d739b-574e-4253-96df-178cefd5f067', $q$Agent Client Protocol$q$, $q$Enables multiple coding agents, including Devin, Codex, and Claude Agent, to run in the same interface post-acquisition.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('758d739b-574e-4253-96df-178cefd5f067', $q$Team and security controls$q$, $q$Admin, security, and access management features available on Teams and Enterprise plans.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('758d739b-574e-4253-96df-178cefd5f067', $q$Powerful agentic capabilities that go beyond simple autocomplete$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('758d739b-574e-4253-96df-178cefd5f067', $q$Supports a broad range of languages and works across popular IDEs$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('758d739b-574e-4253-96df-178cefd5f067', $q$Free tier available for individual developers to try the product$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('758d739b-574e-4253-96df-178cefd5f067', $q$Now backed by Cognition's Devin technology for deeper task automation$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('758d739b-574e-4253-96df-178cefd5f067', $q$Established product with a large existing user base from its Codeium roots$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('758d739b-574e-4253-96df-178cefd5f067', $q$Product direction and branding are in flux following the 2025 Cognition acquisition$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('758d739b-574e-4253-96df-178cefd5f067', $q$Key original founders and researchers left for Google shortly before the acquisition$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('758d739b-574e-4253-96df-178cefd5f067', $q$Users may need to migrate workflows as the product shifts toward Devin Desktop$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('758d739b-574e-4253-96df-178cefd5f067', $q$Per-seat Teams and Enterprise pricing can become costly for larger organizations$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('758d739b-574e-4253-96df-178cefd5f067', $q$What is Windsurf?$q$, $q$Windsurf is an AI-powered code editor built around the Cascade agent, originally developed by the company formerly known as Codeium.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('758d739b-574e-4253-96df-178cefd5f067', $q$Is Windsurf free to use?$q$, $q$Windsurf historically offered a free plan with limited agentic actions, alongside paid Pro, Teams, and Enterprise tiers.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('758d739b-574e-4253-96df-178cefd5f067', $q$What happened to Windsurf after the Cognition acquisition?$q$, $q$In July 2025, Cognition, maker of the Devin coding agent, acquired Windsurf after Google hired away its CEO and key researchers; Cognition has since rebranded the editor as Devin Desktop.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('758d739b-574e-4253-96df-178cefd5f067', $q$What is Devin Desktop?$q$, $q$Devin Desktop is Cognition's rebranded version of the Windsurf editor, built to let multiple AI coding agents, including Devin, run within the same interface via an Agent Client Protocol.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('758d739b-574e-4253-96df-178cefd5f067', $q$Was Windsurf formerly called Codeium?$q$, $q$Yes, the company was originally known as Codeium before launching the Windsurf Editor in November 2024 and completing its rebrand to Windsurf in April 2025.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('758d739b-574e-4253-96df-178cefd5f067', $q$Does Windsurf support VS Code and JetBrains?$q$, $q$Yes, in addition to its standalone editor, Windsurf is available as plugins for VS Code and JetBrains IDEs.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('758d739b-574e-4253-96df-178cefd5f067', $q$How much did Windsurf cost historically?$q$, $q$Reported pricing included a free tier, Pro at 15 dollars per user per month, Teams at 30 dollars per user per month, and Enterprise at 60 dollars per user per month.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('758d739b-574e-4253-96df-178cefd5f067', $q$Agentic feature development$q$, $q$Developers delegate multi-file coding tasks to the Cascade agent to speed up feature implementation.$q$, $q$Individual software developers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('758d739b-574e-4253-96df-178cefd5f067', $q$Team-based AI-assisted coding$q$, $q$Engineering teams use Teams or Enterprise plans for shared AI coding assistance with admin controls.$q$, $q$Software engineering teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('758d739b-574e-4253-96df-178cefd5f067', $q$Multi-agent coding workflows$q$, $q$Developers use the Agent Client Protocol to run several coding agents, including Devin, in one workspace.$q$, $q$Teams adopting autonomous coding agents$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('758d739b-574e-4253-96df-178cefd5f067', $q$Free$q$, $q$$0$q$, $q$monthly$q$, NULL, $q$["Limited agentic actions","Basic AI code completion","Individual use"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('758d739b-574e-4253-96df-178cefd5f067', $q$Pro$q$, $q$$15$q$, $q$per user per month$q$, NULL, $q$["Higher agentic action limits","More model credits","Priority access to features"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('758d739b-574e-4253-96df-178cefd5f067', $q$Teams$q$, $q$$30$q$, $q$per user per month$q$, NULL, $q$["Team collaboration features","Admin controls","Higher usage limits"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('758d739b-574e-4253-96df-178cefd5f067', $q$Enterprise$q$, $q$$60$q$, $q$per user per month$q$, NULL, $q$["Advanced security controls","Organization-wide admin management","Highest usage limits"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('758d739b-574e-4253-96df-178cefd5f067', $q$overview$q$, $q$What Is Windsurf$q$, 2, ARRAY[$q$Windsurf is an AI-powered code editor originally developed by a company founded in 2021 as Codeium. After building an AI code-completion tool, the company launched the Windsurf Editor in November 2024 as one of the first fully agentic IDEs, and completed a full rebrand from Codeium to Windsurf in April 2025.$q$, $q$The centerpiece of the product is Cascade, an AI agent with deep contextual awareness of a codebase that can plan and execute multi-file edits, run terminal commands, and iterate on tasks while keeping the broader project in mind, rather than just suggesting single-line completions.$q$, $q$In 2025 the company underwent major changes: Google hired away its CEO, a co-founder, and key research staff in a large reverse-acquihire, and within days Cognition, maker of the autonomous coding agent Devin, acquired the remaining Windsurf business. Cognition has since rebranded the Windsurf editor as Devin Desktop, positioning it as a shared interface where multiple AI coding agents can operate.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('758d739b-574e-4253-96df-178cefd5f067', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Windsurf's Cascade agent can read and reason across an entire codebase, make coordinated edits across multiple files, run commands, and proactively flag or fix issues, going beyond simple autocomplete to handle more complete development tasks.$q$, $q$The editor supports natural-language-to-code generation, documentation suggestions, and debugging assistance across many programming languages, and is available both as a standalone editor and as extensions for VS Code and JetBrains IDEs.$q$, $q$Following the Cognition acquisition, the product has evolved toward an Agent Client Protocol that lets multiple coding agents, including Codex, Claude Agent, and Devin, operate within the same editor window, reflecting its transition toward a multi-agent coding environment under the Devin Desktop branding.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('758d739b-574e-4253-96df-178cefd5f067', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Historically, Windsurf offered a Free plan with limited agentic actions and model credits, alongside three paid tiers: Pro at 15 dollars per user per month, Teams at 30 dollars per user per month, and Enterprise at 60 dollars per user per month.$q$, $q$Paid tiers added higher usage limits for premium agentic actions and model credits, along with admin, security, and organizational management features aimed at teams and larger companies.$q$, $q$Because Windsurf's product and branding are in transition following the 2025 Cognition acquisition and the shift toward Devin Desktop, prospective buyers should confirm current plan names and pricing directly with Cognition before purchasing.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('aa9d2774-9a4d-4792-8ad7-4de1b095e3bf', $q$Workout planning$q$, $q$Lets users organize and plan upcoming workouts and training blocks.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('aa9d2774-9a4d-4792-8ad7-4de1b095e3bf', $q$Personal record tracking$q$, $q$Logs and monitors personal records and progress over time.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('aa9d2774-9a4d-4792-8ad7-4de1b095e3bf', $q$Smartwatch data integration$q$, $q$Pulls in fitness data from smartwatches without proprietary lock-in.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('aa9d2774-9a4d-4792-8ad7-4de1b095e3bf', $q$Self-hosted Docker deployment$q$, $q$Deploys via Docker Compose or Docker run, with data stored locally.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('aa9d2774-9a4d-4792-8ad7-4de1b095e3bf', $q$No telemetry or tracking$q$, $q$Collects no usage telemetry, prioritizing user privacy and data ownership.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('aa9d2774-9a4d-4792-8ad7-4de1b095e3bf', $q$Statistics dashboards$q$, $q$Provides views of training statistics and progress trends.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('aa9d2774-9a4d-4792-8ad7-4de1b095e3bf', $q$Open-source codebase$q$, $q$Source code is publicly available for inspection and modification under CC BY-NC-SA 4.0.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('aa9d2774-9a4d-4792-8ad7-4de1b095e3bf', $q$Umbrel app store availability$q$, $q$Can be installed directly through the Umbrel home server app store.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('aa9d2774-9a4d-4792-8ad7-4de1b095e3bf', $q$Completely free with no subscriptions or feature gating$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('aa9d2774-9a4d-4792-8ad7-4de1b095e3bf', $q$Full data ownership through self-hosting with no telemetry$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('aa9d2774-9a4d-4792-8ad7-4de1b095e3bf', $q$Lightweight, straightforward Docker-based deployment$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('aa9d2774-9a4d-4792-8ad7-4de1b095e3bf', $q$Actively maintained with frequent releases$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('aa9d2774-9a4d-4792-8ad7-4de1b095e3bf', $q$Smartwatch data support without vendor lock-in$q$, 4);
