INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('aa9d2774-9a4d-4792-8ad7-4de1b095e3bf', $q$Built for individual fitness tracking, not gym, studio, or business management$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('aa9d2774-9a4d-4792-8ad7-4de1b095e3bf', $q$What is Wingfit?$q$, $q$Wingfit is an open-source, self-hosted fitness app for planning workouts, tracking personal records, and syncing smartwatch data.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('aa9d2774-9a4d-4792-8ad7-4de1b095e3bf', $q$Is Wingfit free?$q$, $q$Yes, Wingfit is completely free with no subscriptions, premium tiers, or feature gating.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('aa9d2774-9a4d-4792-8ad7-4de1b095e3bf', $q$Can I self-host Wingfit?$q$, $q$Yes, Wingfit is designed to be self-hosted using Docker Compose or a direct Docker run command.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('aa9d2774-9a4d-4792-8ad7-4de1b095e3bf', $q$What license does Wingfit use?$q$, $q$Wingfit is released under the Creative Commons BY-NC-SA 4.0 license, which allows noncommercial use and modification with attribution.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('aa9d2774-9a4d-4792-8ad7-4de1b095e3bf', $q$Does Wingfit integrate with smartwatches?$q$, $q$Yes, Wingfit can leverage data from smartwatches as part of its workout and progress tracking.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('aa9d2774-9a4d-4792-8ad7-4de1b095e3bf', $q$Who maintains Wingfit?$q$, $q$Wingfit is maintained as an open-source project by an independent developer under the GitHub handle itskovacs.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('aa9d2774-9a4d-4792-8ad7-4de1b095e3bf', $q$Is Wingfit a gym management platform?$q$, $q$No, Wingfit is a personal fitness tracking and workout planning app, not a gym or studio management system.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('aa9d2774-9a4d-4792-8ad7-4de1b095e3bf', $q$Personal workout tracking$q$, $q$Individuals plan training sessions and log personal records without a subscription service.$q$, $q$Individual athletes and fitness enthusiasts$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('aa9d2774-9a4d-4792-8ad7-4de1b095e3bf', $q$Privacy-focused fitness logging$q$, $q$Users who want full ownership of their health data self-host Wingfit instead of using a commercial app.$q$, $q$Privacy-conscious users$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('aa9d2774-9a4d-4792-8ad7-4de1b095e3bf', $q$Home-lab and self-hosting setups$q$, $q$Self-hosting enthusiasts add Wingfit to their home server stack via Docker or Umbrel.$q$, $q$Self-hosting and home-lab enthusiasts$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('aa9d2774-9a4d-4792-8ad7-4de1b095e3bf', $q$Self-Hosted (Open Source)$q$, $q$$0$q$, $q$free, self-hosted$q$, NULL, $q$["Full feature access","No subscriptions or feature gating","Docker-based deployment","Community support"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('aa9d2774-9a4d-4792-8ad7-4de1b095e3bf', $q$overview$q$, $q$What Is Wingfit$q$, 2, ARRAY[$q$Wingfit is a minimalist, open-source fitness application for planning workouts, tracking personal records, and pulling in data from smartwatches. It is developed and maintained as an open-source project on GitHub, with a live demo hosted at wingfit.fr.$q$, $q$Unlike commercial fitness or gym-management SaaS products, Wingfit is built around a privacy-first, self-hosted philosophy. It collects no telemetry, requires no subscription, and gates no features behind a paywall, with the project explicitly emphasizing that users own their own data.$q$, $q$The application is released under the Creative Commons BY-NC-SA 4.0 license, allowing free personal use, inspection, and modification of the source code, while restricting commercial redistribution.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('aa9d2774-9a4d-4792-8ad7-4de1b095e3bf', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Wingfit lets users plan workouts, log personal records, and review progress statistics through a clean, distraction-free interface built with Angular and PrimeNG on the frontend and FastAPI with SQLite on the backend.$q$, $q$The app integrates with smartwatch data, letting users bring in fitness metrics from their existing devices rather than locking them into a single proprietary tracking ecosystem.$q$, $q$Deployment is designed around Docker, with both a recommended Docker Compose setup and a direct Docker run option, making it straightforward to self-host on a home server, NAS, or platforms like Umbrel.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('aa9d2774-9a4d-4792-8ad7-4de1b095e3bf', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Wingfit is completely free to use. There are no subscriptions, no premium tiers, and no feature gating of any kind, since the project's entire value proposition rests on being a free, self-hosted alternative to commercial fitness-tracking subscriptions.$q$, $q$Because it is open source, the only cost involved is whatever infrastructure a user chooses to run it on, such as a home server, NAS, or a small cloud instance running Docker.$q$, $q$There is no enterprise, team, or business pricing tier, since Wingfit is designed for individual, personal use rather than gyms, studios, or corporate wellness programs.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('aa9d2774-9a4d-4792-8ad7-4de1b095e3bf', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('aa9d2774-9a4d-4792-8ad7-4de1b095e3bf', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
