INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b894fce3-7970-4562-8f82-502c745c7472', $q$What is WinterCMS?$q$, $q$WinterCMS is a free, open-source content management system built on the Laravel PHP framework.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b894fce3-7970-4562-8f82-502c745c7472', $q$Is WinterCMS free?$q$, $q$Yes, WinterCMS is free and open source under the MIT license, with no licensing fees.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b894fce3-7970-4562-8f82-502c745c7472', $q$Is WinterCMS the same as October CMS?$q$, $q$WinterCMS began as a fork of October CMS created in March 2021 after October's founders moved the original project to a paid, proprietary model.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b894fce3-7970-4562-8f82-502c745c7472', $q$What is WinterCMS built on?$q$, $q$WinterCMS is built on the Laravel PHP framework.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b894fce3-7970-4562-8f82-502c745c7472', $q$Does WinterCMS have a plugin marketplace?$q$, $q$Yes, WinterCMS offers a plugin and theme marketplace for extending core functionality.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b894fce3-7970-4562-8f82-502c745c7472', $q$Who maintains WinterCMS?$q$, $q$WinterCMS is maintained by a community team under the stewardship of Frostbyte Foundation Inc.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b894fce3-7970-4562-8f82-502c745c7472', $q$Can I migrate from October CMS to WinterCMS?$q$, $q$Because WinterCMS was forked from October CMS's codebase, migration paths exist, though users should review current documentation for compatibility details.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b894fce3-7970-4562-8f82-502c745c7472', $q$Agency website builds$q$, $q$Agencies use WinterCMS to build client websites on a stable, self-hosted, free platform.$q$, $q$Web design and development agencies$q$, 0);
