INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b894fce3-7970-4562-8f82-502c745c7472', $q$Business self-hosted CMS$q$, $q$Businesses that want full control over hosting and data choose WinterCMS over commercial hosted CMS platforms.$q$, $q$Businesses wanting self-hosted infrastructure$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b894fce3-7970-4562-8f82-502c745c7472', $q$Open Source$q$, $q$$0$q$, $q$free, self-hosted$q$, NULL, $q$["Full core CMS functionality","Plugin and theme marketplace access","MIT license","Community support"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b894fce3-7970-4562-8f82-502c745c7472', $q$overview$q$, $q$What Is WinterCMS$q$, 2, ARRAY[$q$WinterCMS is a free, open-source content management system built on the Laravel PHP framework. It was created in March 2021 when a group of core maintainers forked the codebase of October CMS after a breakdown in communication with October's founders.$q$, $q$Following the fork, October CMS's founders made their original product a paid, proprietary platform, while the WinterCMS team committed to keeping their fork free, open source, and governed by the community rather than a single commercial owner.$q$, $q$The project is stewarded by Frostbyte Foundation Inc and built by a team of specialist and agency developers, aiming to serve as a stable, self-hosted alternative for teams that want a Laravel-based CMS without licensing fees.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b894fce3-7970-4562-8f82-502c745c7472', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$WinterCMS focuses on four core strengths: speed through performance-oriented system design, simplicity by letting developers build with standard HTML, CSS, and JavaScript, stability through backwards-compatible updates, and security through full source code transparency.$q$, $q$A plugin and theme architecture, supported by a marketplace, lets developers extend the platform with additional functionality such as e-commerce, forms, and blogging without building everything from scratch.$q$, $q$Being built on Laravel gives WinterCMS access to Laravel's broader tooling, conventions, and developer ecosystem, making it a natural fit for PHP developers already comfortable with that framework.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b894fce3-7970-4562-8f82-502c745c7472', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$WinterCMS is completely free and open source, released under the MIT license, with no cost to download, install, modify, or redistribute the core software.$q$, $q$There is no official managed hosting or SaaS tier from the WinterCMS project itself, so users are responsible for hosting the platform on their own servers or through a third-party hosting provider.$q$, $q$Some plugins and themes distributed through the marketplace may carry their own individual prices set by their developers, though the core CMS and its official features remain free.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b894fce3-7970-4562-8f82-502c745c7472', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
