INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f7b90709-b508-4388-a295-d5608f207c11', $q$WireMock Cloud collaboration$q$, $q$Paid hosted platform adding team collaboration and hybrid deployment options.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f7b90709-b508-4388-a295-d5608f207c11', $q$Mature, widely adopted open-source standard for API mocking$q$, 0);
