INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f7b90709-b508-4388-a295-d5608f207c11', $q$What is WireMock used for?$q$, $q$WireMock is used to simulate APIs and software dependencies so teams can test applications independently, simulate edge cases, and develop in parallel.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f7b90709-b508-4388-a295-d5608f207c11', $q$Is WireMock free?$q$, $q$Yes, the core WireMock library is free and open source for both Java and .NET.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f7b90709-b508-4388-a295-d5608f207c11', $q$What is WireMock Cloud?$q$, $q$WireMock Cloud is a separate, paid platform that adds team collaboration, additional capabilities, and hybrid deployment options.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f7b90709-b508-4388-a295-d5608f207c11', $q$Does WireMock support languages other than Java?$q$, $q$Yes, WireMock also supports .NET in addition to its original Java implementation.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f7b90709-b508-4388-a295-d5608f207c11', $q$Can WireMock record real API responses?$q$, $q$Yes, WireMock can record real service interactions and play them back as mocks.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f7b90709-b508-4388-a295-d5608f207c11', $q$How do I run WireMock in Docker?$q$, $q$WireMock is distributable as a Docker container, in addition to Maven, Gradle, SBT, and standalone JAR options.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f7b90709-b508-4388-a295-d5608f207c11', $q$Who created WireMock?$q$, $q$WireMock's open-source project was created by Tom Akehurst in 2011, who later co-founded WireMock, Inc. with Uri Maoz.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f7b90709-b508-4388-a295-d5608f207c11', $q$Integration testing$q$, $q$QA and backend engineers stub out real dependencies to test services in isolation.$q$, $q$QA and test engineers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f7b90709-b508-4388-a295-d5608f207c11', $q$Parallel frontend and backend development$q$, $q$Frontend teams use mocked APIs to build against expected contracts before backend services are complete.$q$, $q$Frontend and backend developers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f7b90709-b508-4388-a295-d5608f207c11', $q$CI/CD service virtualization$q$, $q$DevOps teams use WireMock or WireMock Cloud to virtualize services within automated pipelines.$q$, $q$DevOps and platform engineering teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f7b90709-b508-4388-a295-d5608f207c11', $q$Open Source$q$, $q$$0$q$, $q$free$q$, NULL, $q$["Full HTTP stubbing and matching","Record and playback","Fault and latency simulation","Java and .NET support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f7b90709-b508-4388-a295-d5608f207c11', $q$WireMock Cloud$q$, $q$Custom$q$, $q$contact sales$q$, NULL, $q$["Team collaboration","Hybrid deployment options","Additional AI-assisted capabilities","Advanced simulation features"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f7b90709-b508-4388-a295-d5608f207c11', $q$overview$q$, $q$What Is WireMock$q$, 2, ARRAY[$q$WireMock is an open-source tool for simulating HTTP-based APIs and software dependencies, used by developers and QA teams to test applications independently of the real services those applications rely on. The open-source project originated in 2011, created by Tom Akehurst, who went on to co-found WireMock, Inc. to build a commercial platform on top of the core tool.$q$, $q$The project is widely described as an industry standard for API simulation, allowing teams to stub out real backend services, simulate edge cases like faults and latency, and enable parallel development between frontend and backend teams.$q$, $q$WireMock's core is free and open source for both Java and .NET, while WireMock Cloud offers a separate, paid, hosted platform aimed at teams that want collaborative API simulation across local, private cloud, and CI/CD environments.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f7b90709-b508-4388-a295-d5608f207c11', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$At its core, WireMock supports HTTP request stubbing and matching based on URLs, headers, query parameters, cookies, and body content, letting teams define precise, predictable mock responses for their tests.$q$, $q$Dynamic response generation is possible through Handlebars templating, and WireMock can record and play back real interactions captured from live services, making it easy to bootstrap realistic mocks. It also supports simulating network faults and delays, and verifying that expected requests were actually made.$q$, $q$The tool is extensible via custom matchers and transformers, can run as a standalone server or embedded library, and integrates with common testing frameworks such as JUnit, with distribution available through Maven, Gradle, SBT, JAR files, and Docker.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f7b90709-b508-4388-a295-d5608f207c11', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$The core WireMock library is completely free and open source, with no licensing cost for using it in personal or commercial testing environments.$q$, $q$WireMock Cloud is a separate, paid platform offering collaboration features, additional simulation capabilities, and hybrid deployment options, aimed at teams that need more than a single-developer, self-hosted setup.$q$, $q$Pricing for WireMock Cloud is not published publicly and requires contacting WireMock directly for a quote based on team size and usage needs.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('f7b90709-b508-4388-a295-d5608f207c11', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
