INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3eb87668-42e1-459d-9212-aea403d70de9', $q$What is Wise Business?$q$, $q$Wise Business is an international multi-currency business account for sending, receiving, and spending money across borders at the mid-market exchange rate.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3eb87668-42e1-459d-9212-aea403d70de9', $q$How much does Wise Business cost?$q$, $q$Wise Business charges a one-time account opening fee of around 60 euros or local equivalent, with no recurring monthly subscription, plus per-transfer fees.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3eb87668-42e1-459d-9212-aea403d70de9', $q$Is Wise Business a bank account?$q$, $q$Wise Business functions as a multi-currency account rather than a traditional bank account, and does not offer overdrafts or lending.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3eb87668-42e1-459d-9212-aea403d70de9', $q$How fast are Wise Business transfers?$q$, $q$Roughly 70 percent of transfers arrive within 20 seconds and 95 percent within 24 hours.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3eb87668-42e1-459d-9212-aea403d70de9', $q$Does Wise Business offer debit cards?$q$, $q$Yes, Wise Business issues physical and digital debit cards usable for spending in 231 countries.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3eb87668-42e1-459d-9212-aea403d70de9', $q$Can Wise Business integrate with accounting software?$q$, $q$Yes, Wise Business connects with popular accounting software to streamline reconciliation and reporting.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3eb87668-42e1-459d-9212-aea403d70de9', $q$Is Wise Business available worldwide?$q$, $q$Wise Business is available to businesses in a large number of countries, though specific eligibility varies by region.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3eb87668-42e1-459d-9212-aea403d70de9', $q$What was Wise previously called?$q$, $q$Wise was originally founded as TransferWise in 2011 and rebranded to Wise in 2021.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3eb87668-42e1-459d-9212-aea403d70de9', $q$Cross-border e-commerce payments$q$, $q$Online sellers receive and hold payments in multiple currencies without excessive conversion fees.$q$, $q$E-commerce businesses$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3eb87668-42e1-459d-9212-aea403d70de9', $q$International team payroll$q$, $q$Startups and scale-ups with international staff use batch payments to pay teams across countries.$q$, $q$Startups and scale-ups with global teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3eb87668-42e1-459d-9212-aea403d70de9', $q$Freelancer and agency invoicing$q$, $q$Freelancers and agencies bill overseas clients and receive payments using local account details.$q$, $q$Freelancers and agencies with international clients$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3eb87668-42e1-459d-9212-aea403d70de9', $q$Wise Business Account$q$, $q$EUR60 one-time fee (or local equivalent)$q$, $q$one-time, plus per-transfer fees$q$, NULL, $q$["Multi-currency balances","Local account details","Debit cards","Batch payments","Accounting integrations"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3eb87668-42e1-459d-9212-aea403d70de9', $q$Volume Discount$q$, $q$Reduced per-transfer fees$q$, $q$usage-based$q$, NULL, $q$["Applies for over EUR20,000 equivalent transferred per month","Lower fees on higher transfer volumes"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3eb87668-42e1-459d-9212-aea403d70de9', $q$overview$q$, $q$What Is Wise Business$q$, 2, ARRAY[$q$Wise Business is the business account product from Wise, a fintech company originally founded as TransferWise in London in January 2011 by Kristo Kaarmann and Taavet Hinrikus, and rebranded to Wise in 2021. The company is headquartered in London and today operates as a large, publicly listed company.$q$, $q$Wise Business is built for startups, scale-ups, freelancers, and small to mid-sized businesses that need to send, receive, hold, and spend money across multiple currencies without relying on a traditional bank account for every market.$q$, $q$The product is reportedly used by more than 700,000 businesses worldwide, processing roughly 14 billion euros in payments each month, built on Wise's core promise of transferring money at the real mid-market exchange rate with transparent fees.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3eb87668-42e1-459d-9212-aea403d70de9', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Businesses can hold balances in over 20 currencies and receive payments using local account details in multiple countries, avoiding the need to open separate local bank accounts. Transfers are fast, with roughly 70 percent arriving within 20 seconds and 95 percent within 24 hours.$q$, $q$Wise Business supports batch payments to up to 1,000 contacts at once, useful for payroll or supplier payments, and issues physical and digital debit cards usable for spending in 231 countries, giving teams direct control over company spend.$q$, $q$The platform integrates with accounting software for streamlined reconciliation, offers team management tools with configurable spending permissions, and lets eligible businesses earn interest on idle balances through Wise Assets Europe.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3eb87668-42e1-459d-9212-aea403d70de9', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Wise Business does not charge a recurring monthly subscription fee. Instead, businesses pay a one-time account opening fee of around 60 euros or the local currency equivalent.$q$, $q$Transfer costs are built into the exchange process using the mid-market rate with transparent, published fees rather than hidden markups on the exchange rate.$q$, $q$Businesses transferring more than roughly 20,000 euros equivalent per month can qualify for volume discounts on transfer fees, making the account more cost-effective as international payment volume grows.$q$]::text[], 2);
