INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4513bb43-aeb2-4840-9feb-1d13971e78ee', $q$What is Wisecut?$q$, $q$Wisecut is an AI-powered video editing platform that turns long videos into short, captioned clips for social media.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4513bb43-aeb2-4840-9feb-1d13971e78ee', $q$Is there a free plan for Wisecut?$q$, $q$Yes, Wisecut offers a Free plan with 30 minutes of processing and a 4GB file size limit.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4513bb43-aeb2-4840-9feb-1d13971e78ee', $q$What is Wisecut Autopilot?$q$, $q$Autopilot is a specialized plan that monitors a YouTube channel and automatically generates short clips from new content.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4513bb43-aeb2-4840-9feb-1d13971e78ee', $q$Does Wisecut support multiple languages for captions?$q$, $q$Yes, Wisecut generates automatic captions and can translate them into multiple languages.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4513bb43-aeb2-4840-9feb-1d13971e78ee', $q$Can Wisecut auto-post to social media?$q$, $q$Yes, the Social Hub feature on Starter+ and Professional+ annual plans supports auto-posting and content scheduling.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4513bb43-aeb2-4840-9feb-1d13971e78ee', $q$What resolutions does Wisecut support?$q$, $q$Wisecut supports up to 1080p on the Starter plan and up to 4K on the Professional plan.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4513bb43-aeb2-4840-9feb-1d13971e78ee', $q$How is Wisecut priced?$q$, $q$Wisecut uses a freemium model with a free tier plus paid Starter, Professional, Autopilot, and custom Enterprise plans.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4513bb43-aeb2-4840-9feb-1d13971e78ee', $q$Podcast clip repurposing$q$, $q$Podcasters turn long recordings into short highlight clips for social media promotion.$q$, $q$Podcasters and audio creators$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4513bb43-aeb2-4840-9feb-1d13971e78ee', $q$Social content scaling$q$, $q$Content creators use AI editing to produce more short-form videos without a dedicated editing team.$q$, $q$Content creators and influencers$q$, 1);
