INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4513bb43-aeb2-4840-9feb-1d13971e78ee', $q$Autopilot$q$, $q$From $49$q$, $q$monthly (annual $588/year)$q$, NULL, $q$["Cloud-based YouTube channel monitoring","Automatic short clip generation"]$q$::jsonb, 5);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4513bb43-aeb2-4840-9feb-1d13971e78ee', $q$Enterprise$q$, $q$Custom$q$, $q$custom quote$q$, NULL, $q$["API access","Custom processing hours","Tailored support"]$q$::jsonb, 6);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4513bb43-aeb2-4840-9feb-1d13971e78ee', $q$overview$q$, $q$What Is Wisecut$q$, 2, ARRAY[$q$Wisecut is an AI-powered video editing platform, based in Miami, Florida, built to turn long-form video footage into short, engaging clips suitable for platforms like TikTok, Instagram Reels, and YouTube Shorts. The company reports its tools are trusted by over 1 million creators and media teams.$q$, $q$The platform is aimed at people who need to repurpose long recordings, such as podcasts, webinars, and livestreams, into short highlight clips quickly, without needing traditional video editing skills or software.$q$, $q$Its core differentiator is AI highlight detection, which automatically scans footage to identify the most engaging moments, significantly reducing the manual effort typically required to find and cut good short-form clips.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4513bb43-aeb2-4840-9feb-1d13971e78ee', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Wisecut generates automatic captions and can translate them into multiple languages, and its transcript-based storyboard editor lets users edit video by editing text, lowering the skill barrier for producing polished clips.$q$, $q$Automated editing tools include silence removal, smart background music selection with automatic audio ducking, auto reframing for vertical, square, or horizontal formats, and punch-in and punch-out zoom effects for emphasis.$q$, $q$Additional features include AI-generated hook titles to improve engagement, and audio enhancement tools such as studio voice refinement and background noise cancellation, along with higher-tier Social Hub tools for auto-posting and scheduling content directly to social platforms.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4513bb43-aeb2-4840-9feb-1d13971e78ee', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Wisecut offers a Free plan with 30 minutes of processing, a 4GB file size limit, and 7-day project retention, alongside paid Starter and Professional monthly plans priced at 15.75 dollars and 75.67 dollars per month respectively.$q$, $q$Annual-billing tiers, Starter+ and Professional+, add Social Hub features like auto-posting, content scheduling, and multi-account management for a discounted monthly-equivalent price when billed yearly.$q$, $q$A specialized Autopilot plan starting around 49 dollars per month monitors a YouTube channel and automatically generates short clips, while an Enterprise plan offers custom pricing for API access and larger processing needs.$q$]::text[], 2);
